solution_code:
#include <iostream>

int handle(int& x)
{
    return x + 1;
}

int handle(int&& x)
{
    return x * 2;
}

int main()
{
    int a{};
    int b{};
    std::cin >> a >> b;

    std::cout << handle(a) << '\n';
    std::cout << handle(a + b) << '\n';
    std::cout << handle(100) << '\n';
    std::cout << handle(b) << '\n';

    return 0;
}

