solution_code:
#include <iostream>

int main()
{
    int a{};
    int b{};
    std::cin >> a >> b;

    int&& ref{ a + b };
    std::cout << ref << '\n';

    ref *= 3;
    std::cout << ref << '\n';

    ref -= 5;
    std::cout << ref << '\n';

    return 0;
}
